mapper.select:
select id, username, password_hash, display_name, enabled
from auth_user
where username = #{username}

select id, username, password_hash, display_name, enabled
from auth_user
where id = #{id}

select id, user_id, token_id, expires_at, revoked
from auth_refresh_token
where token_id = #{tokenId}

mapper.update:
update auth_refresh_token
set revoked = 1
where token_id = #{tokenId}
